PREFIX crm: <http://www.cidoc-crm.org/cidoc-crm/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX skos: <http://www.w3.org/2004/02/skos/core#>

SELECT ?artist ?artistLabel (COUNT(DISTINCT ?obj) as ?workCount)
WHERE {
  {
    ?artist crm:P92i_was_brought_into_existence_by ?birth .
    ?birth crm:P7_took_place_at ?birthPlace .
    ?birthPlace crm:P89_falls_within* <https://data.mahmah.ch/place/a61a6cd3-df3e-584f-a598-3c1c7b935a1b> .
  } UNION {
    ?artist crm:P107i_is_current_or_former_member_of ?group .
    ?group rdfs:label ?gLabel .
    FILTER(CONTAINS(LCASE(?gLabel), 'suisse'))
  }
  ?obj crm:P108i_was_produced_by ?prod .
  ?prod crm:P14_carried_out_by ?artist .
  ?artist skos:prefLabel ?artistLabel .
}
GROUP BY ?artist ?artistLabel
ORDER BY DESC(?workCount)

